        private void GenerarCódigo()
        {
            const string cadena = "AaBbCcDdEeFfGgHhIiJjKkLlMmNnOoPpQqRrSsTtUuVvWwXxYyZz0123456789";
            char[] resultado = new char[6];
            using (var rng = RandomNumberGenerator.Create())
            {
                byte[] datos = new byte[6];
                rng.GetBytes(datos);
                for (int i = 0; i < 6; i++)
                {
                    resultado[i] = cadena[datos[i] % cadena.Length];
                }
            }
            code = new string(resultado);
        }

